patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..29c0a641ce7a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2017,6 +2017,23 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     }
   }

+  // (icmp eq/ne (and (add X, -1), ~2), 0) -> (icmp ne/eq (and X, 1), 0)
+  // This transformation is valid when X is known to be in [0, 4).
+  // For example, with range [0, 4): (X-1) & 0xFD == 0 iff X & 1 != 0
+  {
+    Value *X;
+    const APInt *Addend, *Mask;
+    if (match(And, m_And(m_OneUse(m_Add(m_Value(X), m_APInt(Addend))),
+                         m_APInt(Mask))) &&
+        *Addend == -1 &&
+        ~*Mask == 2) {
+      Value *NewAnd = Builder.CreateAnd(X, ConstantInt::get(X->getType(), 1));
+      auto NewPred = Pred == CmpInst::ICMP_EQ ? CmpInst::ICMP_NE : CmpInst::ICMP_EQ;
+      return new ICmpInst(NewPred, NewAnd, Cmp.getOperand(1));
+    }
+  }
+
+  return nullptr;
   return nullptr;
 }

